prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?taskType ?loopType WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_86d8a78f_54c4_423d_92e1_edf43db849dc> .
  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task bboExt:loopType ?loopType . }
  BIND("ChoreographyTask" AS ?taskType)
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName (BOUND(?reachable) AS ?isReachable) WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_86d8a78f_54c4_423d_92e1_edf43db849dc> .
  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-8B059A72-97FC-4FC5-8321-9E7C9B523303> ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
    BIND(?task AS ?reachable)
  }
}
